import React, { useState, useEffect } from 'react';

function App() {
  const [books, setBooks] = useState([]);
  const [error, setError] = useState(null);
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedCategory, setSelectedCategory] = useState('All');
  const [cart, setCart] = useState([]);

  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const [username, setUsername] = useState('');
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [authMode, setAuthMode] = useState('login');
  const [authError, setAuthError] = useState(null);

  const [showCheckoutModal, setShowCheckoutModal] = useState(false);

  const [sortBy, setSortBy] = useState('none');
  const [currentPage, setCurrentPage] = useState(1);
  const booksPerPage = 10;

  const [isAdmin, setIsAdmin] = useState(false);
  const [newTitle, setNewTitle] = useState('');
  const [newAuthor, setNewAuthor] = useState('');
  const [newPrice, setNewPrice] = useState('');
  const [newCategory, setNewCategory] = useState('Stories');
  const [showAddModal, setShowAddModal] = useState(false);

  useEffect(() => {
    if (isLoggedIn) {
      fetch('http://localhost:5000/api/products')
        .then(res => {
          if (!res.ok) {
            throw new Error('Server returned status: ' + res.status);
          }
          return res.json();
        })
        .then(data => setBooks(data))
        .catch(err => {
          console.error(err);
          setError('Failed to load books: ' + err.message);
        });
    }
  }, [isLoggedIn]);

  const handleAuth = (e) => {
    e.preventDefault();
    setAuthError(null);

    if (authMode === 'login') {
      if (email === 'admin@deci.com' && password === '0000') {
        setIsAdmin(true);
        setUsername('Admin');
        setIsLoggedIn(true);
        return;
      }

      fetch('http://localhost:5000/api/auth/login', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ email, password })
      })
        .then(res => {
          if (!res.ok) {
            throw new Error('Invalid email or password');
          }
          return res.json();
        })
        .then(data => {
          if (email === 'admin@deci.com') {
            setIsAdmin(true);
            setUsername('Admin');
          } else {
            const nameFromEmail = email.split('@')[0];
            setUsername(nameFromEmail.charAt(0).toUpperCase() + nameFromEmail.slice(1));
          }
          setIsLoggedIn(true);
        })
        .catch(err => {
          setAuthError(err.message);
        });
    } else {
      if (username.trim() === '') {
        setAuthError('Please enter a username');
        return;
      }
      setIsLoggedIn(true);
    }
  };

  const handleLogout = () => {
    setIsLoggedIn(false);
    setIsAdmin(false);
    setEmail('');
    setPassword('');
    setCart([]);
    if (authMode === 'login') setUsername('');
  };

  const addToCart = (book) => {
    setCart([...cart, book]);
  };

  const removeFromCart = (indexToRemove) => {
    setCart(cart.filter((_, index) => index !== indexToRemove));
  };

  const confirmCheckout = () => {
    setCart([]);
    setShowCheckoutModal(false);
  };

  const handleAddBook = (e) => {
    e.preventDefault();
    
    const newBookId = Date.now(); 
    const bookData = { 
      id: newBookId, 
      title: newTitle, 
      author: newAuthor, 
      price: parseFloat(newPrice), 
      category: newCategory 
    };
    
    setBooks([...books, bookData]);
    setShowAddModal(false);
    setNewTitle(''); 
    setNewAuthor(''); 
    setNewPrice('');

    fetch('http://localhost:5000/api/products', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        title: newTitle,
        author: newAuthor,
        price: parseFloat(newPrice),
        category: newCategory
      })
    })
    .then(res => {
      if (!res.ok) console.error('Server failed to save, but added locally');
      return res.json();
    })
    .catch(err => console.error('Network error, book kept locally:', err));
  };

  const handleDeleteBook = (id) => {
    fetch(`http://localhost:5000/api/products/${id}`, { method: 'DELETE' })
      .then(() => {
        setBooks(books.filter(book => book.id !== id));
      });
  };

  const cartTotal = cart.reduce((total, book) => total + book.price, 0);

  const filtered = books.filter(book => {
    const matchesSearch = book.title.toLowerCase().includes(searchTerm.toLowerCase()) || 
                          book.author.toLowerCase().includes(searchTerm.toLowerCase());
    const matchesCategory = selectedCategory === 'All' || book.category === selectedCategory;
    return matchesSearch && matchesCategory;
  });

  const sortedBooks = [...filtered].sort((a, b) => {
    if (sortBy === 'low-to-high') return a.price - b.price;
    if (sortBy === 'high-to-low') return b.price - a.price;
    return 0;
  });

  const indexOfLastBook = currentPage * booksPerPage;
  const indexOfFirstBook = indexOfLastBook - booksPerPage;
  const currentBooks = sortedBooks.slice(indexOfFirstBook, indexOfLastBook);
  const totalPages = Math.ceil(sortedBooks.length / booksPerPage);

  if (!isLoggedIn) {
    return (
      <div style={{ display: 'flex', minHeight: '100vh', backgroundColor: '#fafafa', fontFamily: '"Segoe UI", -apple-system, BlinkMacSystemFont, Roboto, sans-serif' }}>
        <div style={{ flex: '1', display: 'flex', flexDirection: 'column', justifyContent: 'center', padding: '0 10%', backgroundColor: '#ffffff', maxWidth: '480px', boxShadow: '10px 0 40px rgba(0,0,0,0.03)', zIndex: 2 }}>
          <div style={{ marginBottom: '40px' }}>
            <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', width: '22px', height: '22px', gap: '2px', marginBottom: '16px' }}>
              <div style={{ backgroundColor: '#f25022' }}></div>
              <div style={{ backgroundColor: '#7fbb00' }}></div>
              <div style={{ backgroundColor: '#00a1f1' }}></div>
              <div style={{ backgroundColor: '#ffb900' }}></div>
            </div>
            <h2 style={{ fontSize: '32px', fontWeight: '600', color: '#1b1b1b', margin: '0 0 8px 0', letterSpacing: '-0.5px' }}>
              {authMode === 'login' ? 'Sign in' : 'Create account'}
            </h2>
            <p style={{ color: '#505050', fontSize: '15px', margin: 0 }}>
              {authMode === 'login' ? 'to continue to Z-BOOK Cloud Marketplace' : 'to start your global enterprise workspace'}
            </p>
          </div>

          {authError && (
            <div style={{ color: '#d83b01', backgroundColor: '#fde7e9', borderLeft: '3px solid #d83b01', padding: '12px 16px', fontSize: '14px', marginBottom: '24px' }}>
              {authError}
            </div>
          )}

          <form onSubmit={handleAuth} style={{ display: 'flex', flexDirection: 'column', gap: '20px' }}>
            {authMode === 'signup' && (
              <div>
                <input 
                  id="username-input"
                  type="text" 
                  placeholder="Username"
                  required
                  value={username}
                  onChange={(e) => setUsername(e.target.value)}
                  style={{ width: '100%', padding: '10px 12px', border: '1px solid #666666', backgroundColor: '#ffffff', color: '#1b1b1b', boxSizing: 'border-box', fontSize: '15px', outline: 'none', transition: 'border-color 0.2s' }}
                />
              </div>
            )}

            <div>
              <input 
                id="email-input"
                type="email" 
                placeholder="Email, phone, or Skype"
                required
                value={email}
                onChange={(e) => setEmail(e.target.value)}
                style={{ width: '100%', padding: '10px 12px', border: '1px solid #666666', backgroundColor: '#ffffff', color: '#1b1b1b', boxSizing: 'border-box', fontSize: '15px', outline: 'none', transition: 'border-color 0.2s' }}
              />
            </div>

            <div>
              <input 
                id="password-input"
                type="password" 
                placeholder="Password"
                required
                value={password}
                onChange={(e) => setPassword(e.target.value)}
                style={{ width: '100%', padding: '10px 12px', border: '1px solid #666666', backgroundColor: '#ffffff', color: '#1b1b1b', boxSizing: 'border-box', fontSize: '15px', outline: 'none', transition: 'border-color 0.2s' }}
              />
            </div>

            <div style={{ fontSize: '13px', color: '#505050', marginTop: '4px' }}>
              {authMode === 'login' ? "No account? " : "Already have an account? "}
              <span 
                onClick={() => { setAuthMode(authMode === 'login' ? 'signup' : 'login'); setAuthError(null); }}
                style={{ color: '#0067b8', cursor: 'pointer', textDecoration: 'none' }}
              >
                {authMode === 'login' ? 'Create one!' : 'Sign in'}
              </span>
            </div>

            <div style={{ display: 'flex', justifyContent: 'flex-end', marginTop: '20px' }}>
              <button type="submit" style={{ backgroundColor: '#0067b8', color: '#ffffff', border: 'none', padding: '8px 32px', minWidth: '108px', height: '36px', cursor: 'pointer', fontWeight: '400', fontSize: '15px', transition: 'background-color 0.2s' }}>
                {authMode === 'login' ? 'Next' : 'Submit'}
              </button>
            </div>
          </form>
        </div>

        <div style={{ flex: '1', position: 'relative', overflow: 'hidden', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
          <img 
            src="https://images.unsplash.com/photo-1497366216548-37526070297c?auto=format&fit=crop&w=1200&q=80" 
            alt="Corporate Environment" 
            style={{ position: 'absolute', width: '100%', height: '100%', objectFit: 'cover', zIndex: 1 }}
          />
          <div style={{ position: 'absolute', top: 0, left: 0, width: '100%', height: '100%', background: 'linear-gradient(135deg, rgba(0,103,184,0.85) 0%, rgba(10,25,47,0.9) 100%)', zIndex: 1 }}></div>
          <div style={{ position: 'relative', zIndex: 2, padding: '40px', color: '#ffffff', maxWidth: '500px', textAlign: 'left' }}>
            <h1 style={{ fontSize: '40px', fontWeight: '300', margin: '0 0 16px 0', lineHeight: '1.2' }}>Empowering architectural discovery globally.</h1>
            <p style={{ fontSize: '18px', color: 'rgba(255,255,255,0.8)', margin: 0, fontWeight: '300', lineHeight: '1.5' }}>Access premium research repositories, corporate digital assets, and high-performance development documentation instantly.</p>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div style={{ fontFamily: '"Segoe UI", -apple-system, BlinkMacSystemFont, Roboto, sans-serif', backgroundColor: '#f2f2f2', color: '#242424', minHeight: '100vh', display: 'flex', flexDirection: 'column' }}>
      
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', backgroundColor: '#ffffff', padding: '0 5%', height: '48px', borderBottom: '1px solid rgba(0,0,0,0.06)', position: 'sticky', top: 0, zIndex: 100 }}>
        <div style={{ display: 'flex', alignItems: 'center', gap: '30px' }}>
          <div style={{ display: 'flex', alignItems: 'center', gap: '10px' }}>
            <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', width: '16px', height: '16px', gap: '1px' }}>
              <div style={{ backgroundColor: '#f25022' }}></div>
              <div style={{ backgroundColor: '#7fbb00' }}></div>
              <div style={{ backgroundColor: '#00a1f1' }}></div>
              <div style={{ backgroundColor: '#ffb900' }}></div>
            </div>
            <span style={{ fontWeight: '600', color: '#242424', fontSize: '16px', letterSpacing: '-0.3px' }}>Z-BOOK</span>
          </div>
          <nav style={{ display: 'flex', gap: '24px', fontSize: '13px', color: '#616161' }}>
            <span style={{ cursor: 'pointer', color: '#242424', borderBottom: '2px solid #0067b8', padding: '13px 0' }}>Enterprise Marketplace</span>
            <span style={{ cursor: 'pointer', padding: '13px 0' }}>Documentation</span>
            <span style={{ cursor: 'pointer', padding: '13px 0' }}>Cloud Solutions</span>
          </nav>
        </div>
        
        <div style={{ display: 'flex', alignItems: 'center', gap: '20px' }}>
          <span style={{ fontSize: '13px', color: '#616161' }}>Active Account: <strong style={{ color: '#242424' }}>{username}</strong></span>
          <button onClick={handleLogout} style={{ backgroundColor: 'transparent', color: '#0067b8', border: 'none', padding: '6px 12px', cursor: 'pointer', fontSize: '13px', hover: { textDecoration: 'underline' } }}>Sign out</button>
        </div>
      </div>

      <div style={{ position: 'relative', height: '320px', overflow: 'hidden', display: 'flex', alignItems: 'center', padding: '0 5%' }}>
        <img 
          src="https://images.unsplash.com/photo-1451187580459-43490279c0fa?auto=format&fit=crop&w=1600&q=80" 
          alt="Banner Tech Infrastructure" 
          style={{ position: 'absolute', top: 0, left: 0, width: '100%', height: '100%', objectFit: 'cover', zIndex: 1 }}
        />
        <div style={{ position: 'absolute', top: 0, left: 0, width: '100%', height: '100%', background: 'linear-gradient(to right, rgba(255,255,255,1) 30%, rgba(255,255,255,0.2) 100%)', zIndex: 2 }}></div>
        <div style={{ position: 'relative', zIndex: 3, maxWidth: '540px' }}>
          <span style={{ backgroundColor: '#ffb900', color: '#000000', padding: '4px 8px', fontSize: '11px', fontWeight: '600', textTransform: 'uppercase', display: 'inline-block', marginBottom: '12px' }}>Enterprise Library</span>
          <h2 style={{ fontSize: '36px', fontWeight: '300', margin: '0 0 12px 0', color: '#000000', lineHeight: '1.2' }}>The platform for critical knowledge management.</h2>
          <p style={{ fontSize: '15px', color: '#505050', margin: 0, lineHeight: '1.5' }}>Streamline your organization's intellectual resources with high-performance storage infrastructure and encrypted delivery architectures.</p>
        </div>
      </div>

      {isAdmin ? (
        <div style={{ padding: '40px 5%', flex: 1 }}>
          <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '24px', backgroundColor: '#ffffff', padding: '24px', border: '1px solid rgba(0,0,0,0.06)' }}>
            <div>
              <h2 style={{ margin: 0, color: '#242424', fontSize: '20px', fontWeight: '600' }}>Admin Operations Center</h2>
              <p style={{ margin: '4px 0 0 0', color: '#616161', fontSize: '13px' }}>Configure asset indexes, catalogue schemas and operational properties.</p>
            </div>
            <button onClick={() => setShowAddModal(true)} style={{ backgroundColor: '#0067b8', color: '#ffffff', border: 'none', padding: '8px 24px', cursor: 'pointer', fontSize: '14px', fontWeight: '400' }}>Index New Asset</button>
          </div>

          <div style={{ backgroundColor: '#ffffff', border: '1px solid rgba(0,0,0,0.06)', overflowX: 'auto' }}>
            <table style={{ width: '100%', borderCollapse: 'collapse', textAlign: 'left' }}>
              <thead>
                <tr style={{ borderBottom: '1px solid rgba(0,0,0,0.08)', backgroundColor: '#fcfcfc' }}>
                  <th style={{ padding: '14px 20px', color: '#242424', fontSize: '13px', fontWeight: '600' }}>Resource Name</th>
                  <th style={{ padding: '14px 20px', color: '#242424', fontSize: '13px', fontWeight: '600' }}>Originator / Author</th>
                  <th style={{ padding: '14px 20px', color: '#242424', fontSize: '13px', fontWeight: '600' }}>Classification</th>
                  <th style={{ padding: '14px 20px', color: '#242424', fontSize: '13px', fontWeight: '600' }}>Valuation Price</th>
                  <th style={{ padding: '14px 20px', color: '#242424', fontSize: '13px', fontWeight: '600', textAlign: 'right' }}>Management</th>
                </tr>
              </thead>
              <tbody>
                {books.map(book => (
                  <tr key={book.id} style={{ borderBottom: '1px solid rgba(0,0,0,0.04)', ':hover': { backgroundColor: '#f9f9f9' } }}>
                    <td style={{ padding: '16px 20px', fontWeight: '600', color: '#0067b8', fontSize: '14px' }}>{book.title}</td>
                    <td style={{ padding: '16px 20px', color: '#616161', fontSize: '14px' }}>{book.author}</td>
                    <td style={{ padding: '16px 20px' }}>
                      <span style={{ border: '1px solid #e5e5e5', backgroundColor: '#f3f3f3', color: '#242424', padding: '2px 8px', fontSize: '12px' }}>{book.category}</span>
                    </td>
                    <td style={{ padding: '16px 20px', color: '#242424', fontWeight: '600', fontSize: '14px' }}>${book.price.toFixed(2)}</td>
                    <td style={{ padding: '16px 20px', textAlign: 'right' }}>
                      <button onClick={() => handleDeleteBook(book.id)} style={{ backgroundColor: 'transparent', color: '#a80000', border: 'none', cursor: 'pointer', fontSize: '13px', fontWeight: '600' }}>Decommission</button>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      ) : (
        <div style={{ display: 'flex', padding: '40px 5%', gap: '40px', alignItems: 'flex-start', flex: 1 }}>
          
          <div style={{ flex: '1' }}>
            {error && (
              <div style={{ color: '#a80000', backgroundColor: '#fde7e9', borderLeft: '3px solid #a80000', padding: '16px', marginBottom: '32px', fontSize: '14px' }}>
                {error}
              </div>
            )}

            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', gap: '20px', marginBottom: '32px', backgroundColor: '#ffffff', padding: '16px 24px', border: '1px solid rgba(0,0,0,0.05)' }}>
              <div style={{ display: 'flex', gap: '8px' }}>
                {['All', 'Stories', 'Science', 'History', 'Tech'].map(category => (
                  <button 
                    key={category}
                    onClick={() => { setSelectedCategory(category); setCurrentPage(1); }}
                    style={{
                      padding: '6px 16px',
                      border: 'none',
                      cursor: 'pointer',
                      fontSize: '13px',
                      backgroundColor: selectedCategory === category ? '#0067b8' : 'transparent',
                      color: selectedCategory === category ? '#ffffff' : '#242424',
                      transition: 'all 0.15s ease'
                    }}
                  >
                    {category}
                  </button>
                ))}
              </div>

              <div style={{ display: 'flex', alignItems: 'center', gap: '16px' }}>
                <input 
                  type="text" 
                  placeholder="Search resources..." 
                  value={searchTerm}
                  onChange={(e) => { setSearchTerm(e.target.value); setCurrentPage(1); }}
                  style={{ 
                    padding: '6px 12px', 
                    width: '240px', 
                    border: '1px solid #767676', 
                    backgroundColor: '#ffffff',
                    color: '#242424',
                    fontSize: '14px',
                    outline: 'none'
                  }}
                />

                <select 
                  id="sort-select"
                  value={sortBy} 
                  onChange={(e) => { setSortBy(e.target.value); setCurrentPage(1); }}
                  style={{ padding: '6px 12px', border: '1px solid #767676', backgroundColor: '#ffffff', color: '#242424', outline: 'none', cursor: 'pointer', fontSize: '14px' }}
                >
                  <option value="none">Sort: Default</option>
                  <option value="low-to-high">Price: Low to High</option>
                  <option value="high-to-low">Price: High to Low</option>
                </select>
              </div>
            </div>
            
            <div style={{ 
              display: 'grid', 
              gridTemplateColumns: 'repeat(auto-fill, minmax(280px, 1fr))', 
              gap: '24px'
            }}>
              {currentBooks.map(book => (
                <div key={book.id} style={{ 
                  backgroundColor: '#ffffff', 
                  border: '1px solid rgba(0,0,0,0.06)',
                  display: 'flex', 
                  flexDirection: 'column',
                  transition: 'box-shadow 0.2s ease',
                  boxShadow: '0 2px 4px rgba(0,0,0,0.02)'
                }}>
                  <div style={{ width: '100%', height: '180px', overflow: 'hidden', position: 'relative' }}>
                    <img 
                      src={
                        book.category === 'Science' ? 'https://images.unsplash.com/photo-1507679799987-c73779587ccf?auto=format&fit=crop&w=600&q=80' :
                        book.category === 'Tech' ? 'https://images.unsplash.com/photo-1488590528505-98d2b5aba04b?auto=format&fit=crop&w=600&q=80' :
                        book.category === 'History' ? 'https://images.unsplash.com/photo-1461360370896-922624d12aa1?auto=format&fit=crop&w=600&q=80' :
                        'https://images.unsplash.com/photo-1434030216411-0b793f4b4173?auto=format&fit=crop&w=600&q=80'
                      } 
                      alt="Publication Cover Architecture" 
                      style={{ width: '100%', height: '100%', objectFit: 'cover' }}
                    />
                  </div>
                  <div style={{ padding: '20px', display: 'flex', flexDirection: 'column', flex: 1 }}>
                    <span style={{ fontSize: '11px', fontWeight: '600', color: '#0067b8', textTransform: 'uppercase', letterSpacing: '0.5px', marginBottom: '6px' }}>{book.category}</span>
                    <h3 style={{ margin: '0 0 4px 0', color: '#242424', fontSize: '18px', fontWeight: '300', lineHeight: '1.3' }}>{book.title}</h3>
                    <p style={{ margin: '0 0 20px 0', color: '#616161', fontSize: '13px' }}>By {book.author}</p>
                    
                    <div style={{ marginTop: 'auto', display: 'flex', alignItems: 'center', justifyContent: 'space-between', paddingTop: '16px', borderTop: '1px solid #f2f2f2' }}>
                      <span style={{ fontWeight: '600', color: '#242424', fontSize: '18px' }}>${book.price.toFixed(2)}</span>
                      <button 
                        onClick={() => addToCart(book)}
                        style={{ 
                          backgroundColor: 'transparent', 
                          color: '#0067b8', 
                          border: 'none', 
                          padding: '4px 0', 
                          cursor: 'pointer', 
                          fontWeight: '600',
                          fontSize: '14px',
                          display: 'flex',
                          alignItems: 'center',
                          gap: '6px'
                        }}
                      >
                        Add to cluster →
                      </button>
                    </div>
                  </div>
                </div>
              ))}
            </div>

            {currentBooks.length === 0 && (
              <p style={{ textAlign: 'center', color: '#616161', fontSize: '14px', marginTop: '40px' }}>No systematic resources found under current configurations.</p>
            )}

            {totalPages > 1 && (
              <div style={{ display: 'flex', justifyContent: 'flex-start', alignItems: 'center', gap: '8px', marginTop: '32px' }}>
                <button 
                  disabled={currentPage === 1}
                  onClick={() => setCurrentPage(prev => prev - 1)}
                  style={{ padding: '6px 12px', border: '1px solid #e5e5e5', backgroundColor: '#ffffff', color: '#242424', cursor: currentPage === 1 ? 'not-allowed' : 'pointer', fontSize: '13px' }}
                >
                  Previous
                </button>
                <span style={{ fontSize: '13px', color: '#616161', padding: '0 8px' }}>Page {currentPage} of {totalPages}</span>
                <button 
                  disabled={currentPage === totalPages}
                  onClick={() => setCurrentPage(prev => prev + 1)}
                  style={{ padding: '6px 12px', border: '1px solid #e5e5e5', backgroundColor: '#ffffff', color: '#242424', cursor: currentPage === totalPages ? 'not-allowed' : 'pointer', fontSize: '13px' }}
                >
                  Next
                </button>
              </div>
            )}
          </div>

          <div style={{ 
            width: '320px', 
            backgroundColor: '#ffffff', 
            padding: '24px', 
            border: '1px solid rgba(0,0,0,0.06)',
            boxSizing: 'border-box'
          }}>
            <h2 style={{ color: '#242424', paddingBottom: '12px', borderBottom: '1px solid #e5e5e5', margin: 0, fontSize: '16px', fontWeight: '600' }}>Staging Manifest ({cart.length})</h2>
            
            <div style={{ margin: '16px 0', minHeight: '120px' }}>
              {cart.length === 0 ? (
                <div style={{ color: '#616161', fontSize: '13px', paddingTop: '20px', textAlign: 'center' }}>
                  No digital assets staged for deployment.
                </div>
              ) : (
                <ul style={{ listStyle: 'none', padding: 0, margin: 0, display: 'flex', flexDirection: 'column', gap: '8px' }}>
                  {cart.map((item, index) => (
                    <li key={index} style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', fontSize: '13px', backgroundColor: '#fcfcfc', padding: '8px', border: '1px solid #f2f2f2' }}>
                      <div style={{ flex: 1, paddingRight: '12px' }}>
                        <span style={{ display: 'block', fontWeight: '600', color: '#242424' }}>{item.title}</span>
                        <span style={{ color: '#616161' }}>${item.price.toFixed(2)}</span>
                      </div>
                      <button 
                        onClick={() => removeFromCart(index)}
                        style={{ backgroundColor: 'transparent', color: '#a80000', border: 'none', cursor: 'pointer', fontSize: '11px', padding: 0 }}
                      >
                        Remove
                      </button>
                    </li>
                  ))}
                </ul>
              )}
            </div>

            <div style={{ borderTop: '1px solid #e5e5e5', paddingTop: '16px' }}>
              <div style={{ display: 'flex', justifyContent: 'space-between', fontSize: '14px', marginBottom: '16px' }}>
                <span style={{ color: '#616161' }}>Aggregate Cost</span>
                <span style={{ color: '#242424', fontWeight: '600', fontSize: '16px' }}>${cartTotal.toFixed(2)}</span>
              </div>
              <button 
                onClick={() => setShowCheckoutModal(true)}
                disabled={cart.length === 0}
                style={{ 
                  backgroundColor: cart.length === 0 ? '#f3f3f3' : '#0067b8', 
                  color: cart.length === 0 ? '#919191' : '#ffffff', 
                  border: 'none', 
                  padding: '10px', 
                  cursor: cart.length === 0 ? 'not-allowed' : 'pointer', 
                  fontWeight: '400',
                  width: '100%',
                  fontSize: '14px'
                }}
              >
                Execute Licensing Contract
              </button>
            </div>
          </div>
        </div>
      )}

      {showCheckoutModal && (
        <div style={{ position: 'fixed', top: 0, left: 0, width: '100%', height: '100%', backgroundColor: 'rgba(0,0,0,0.4)', display: 'flex', justifyContent: 'center', alignItems: 'center', zIndex: 1000 }}>
          <div style={{ backgroundColor: '#ffffff', padding: '32px', width: '100%', maxWidth: '440px', boxSizing: 'border-box', border: '1px solid rgba(0,0,0,0.1)' }}>
            <h3 style={{ margin: '0 0 12px 0', color: '#242424', fontSize: '20px', fontWeight: '300' }}>Deployment Provisioned</h3>
            <p style={{ color: '#616161', fontSize: '14px', marginBottom: '24px', lineHeight: '1.5' }}>
              Transaction successfully logged for operator <strong>{username}</strong>. A collection of <strong>{cart.length}</strong> cloud assets has been compiled for a net consideration of <strong>${cartTotal.toFixed(2)}</strong>.
            </p>
            <div style={{ display: 'flex', justifyContent: 'flex-end' }}>
              <button 
                onClick={confirmCheckout}
                style={{ backgroundColor: '#0067b8', color: '#ffffff', border: 'none', padding: '8px 24px', cursor: 'pointer', fontSize: '14px' }}
              >
                Acknowledge and Clear
              </button>
            </div>
          </div>
        </div>
      )}

      {showAddModal && (
        <div style={{ position: 'fixed', top: 0, left: 0, width: '100%', height: '100%', backgroundColor: 'rgba(0,0,0,0.4)', display: 'flex', justifyContent: 'center', alignItems: 'center', zIndex: 2000 }}>
          <form onSubmit={handleAddBook} style={{ backgroundColor: '#ffffff', padding: '32px', width: '100%', maxWidth: '400px', boxSizing: 'border-box' }}>
            <h3 style={{ marginTop: 0, marginBottom: '20px', color: '#242424', fontSize: '18px', fontWeight: '600' }}>Index New Publication</h3>
            <div style={{ marginBottom: '16px' }}>
              <label htmlFor="new-title" style={{ display: 'block', marginBottom: '4px', color: '#242424', fontSize: '13px' }}>Asset Title</label>
              <input id="new-title" type="text" required value={newTitle} onChange={(e) => setNewTitle(e.target.value)} style={{ width: '100%', padding: '8px', border: '1px solid #767676', backgroundColor: '#ffffff', color: '#242424', boxSizing: 'border-box', outline: 'none', fontSize: '14px' }} />
            </div>
            <div style={{ marginBottom: '16px' }}>
              <label htmlFor="new-author" style={{ display: 'block', marginBottom: '4px', color: '#242424', fontSize: '13px' }}>Primary Originator</label>
              <input id="new-author" type="text" required value={newAuthor} onChange={(e) => setNewAuthor(e.target.value)} style={{ width: '100%', padding: '8px', border: '1px solid #767676', backgroundColor: '#ffffff', color: '#242424', boxSizing: 'border-box', outline: 'none', fontSize: '14px' }} />
            </div>
            <div style={{ marginBottom: '16px' }}>
              <label htmlFor="new-price" style={{ display: 'block', marginBottom: '4px', color: '#242424', fontSize: '13px' }}>Corporate Valuation ($)</label>
              <input id="new-price" type="number" step="0.01" required value={newPrice} onChange={(e) => setNewPrice(e.target.value)} style={{ width: '100%', padding: '8px', border: '1px solid #767676', backgroundColor: '#ffffff', color: '#242424', boxSizing: 'border-box', outline: 'none', fontSize: '14px' }} />
            </div>
            <div style={{ marginBottom: '24px' }}>
              <label htmlFor="new-category" style={{ display: 'block', marginBottom: '4px', color: '#242424', fontSize: '13px' }}>Systemic Classification</label>
              <select id="new-category" value={newCategory} onChange={(e) => setNewCategory(e.target.value)} style={{ width: '100%', padding: '8px', border: '1px solid #767676', backgroundColor: '#ffffff', color: '#242424', boxSizing: 'border-box', outline: 'none', fontSize: '14px', cursor: 'pointer' }}>
                <option value="Stories">Stories</option>
                <option value="Science">Science</option>
                <option value="History">History</option>
                <option value="Tech">Tech</option>
              </select>
            </div>
            <div style={{ display: 'flex', justifyContent: 'flex-end', gap: '12px' }}>
              <button type="button" onClick={() => setShowAddModal(false)} style={{ padding: '6px 16px', background: 'transparent', border: '1px solid #767676', color: '#242424', cursor: 'pointer', fontSize: '14px' }}>Cancel</button>
              <button type="submit" style={{ padding: '6px 20px', backgroundColor: '#0067b8', color: '#ffffff', border: 'none', cursor: 'pointer', fontSize: '14px' }}>Commit Entry</button>
            </div>
          </form>
        </div>
      )}

      <footer style={{ backgroundColor: '#242424', color: '#868686', padding: '32px 5%', fontSize: '12px', marginTop: 'auto', borderTop: '1px solid rgba(0,0,0,0.1)' }}>
        <div style={{ display: 'flex', justifyContent: 'space-between', flexWrap: 'wrap', gap: '20px' }}>
          <div>© {new Date().getFullYear()} Z-BOOK Corporation. All engineering rights reserved.</div>
          <div style={{ display: 'flex', gap: '20px' }}>
            <span style={{ cursor: 'pointer' }}>Privacy & Cookies</span>
            <span style={{ cursor: 'pointer' }}>Terms of Corporate Use</span>
            <span style={{ cursor: 'pointer' }}>Trademarks</span>
          </div>
        </div>
      </footer>

    </div>
  );
}

export default App;
